# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

local filename = ngx.var.arg_file
if not filename then
    ngx.status = 400
    ngx.say("File parameter required")
    ngx.exit(400)
end

local base_dir = "./files/"
local path = base_dir .. filename

-- Canonicalize path
local canonical_path = path:gsub("/+", "/")
canonical_path = canonical_path:gsub("/%./", "/")
canonical_path = canonical_path:gsub("/%.$", "")

-- Resolve .. components
while canonical_path:find("/%.%./") do
    canonical_path = canonical_path:gsub("/[^/]+/%.%./", "/")
end

-- Ensure path stays within base directory
if not canonical_path:find("^" .. base_dir) then
    ngx.status = 403
    ngx.say("Access denied")
    ngx.exit(403)
end

-- Check if file exists and is readable
local file = io.open(canonical_path, "r")
if not file then
    ngx.status = 404
    ngx.say("File not found")
    ngx.exit(404)
end

-- Read and serve file content
local content = file:read("*a")
file:close()

ngx.say(content)